import{c as a,Q as t,j as o,m as r}from"./chunks/framework.BA1dEi98.js";const i="/librislog/next/screenshots/profile.png",u=JSON.parse('{"title":"Profile","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/profile.md","filePath":"guide/using-librislog/profile.md","lastUpdated":1780122781000}'),n={name:"guide/using-librislog/profile.md"};function s(l,e,d,h,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h1><p>The profile page is your personal settings hub. Access it by clicking your avatar or name in the top-right corner and selecting &quot;Profile&quot;.</p><p><img src="'+i+'" alt="Profile page" loading="lazy"></p><h2 id="profile-information" tabindex="-1">Profile Information <a class="header-anchor" href="#profile-information" aria-label="Permalink to &quot;Profile Information&quot;">​</a></h2><p>Update your first name, last name, or password. The password field is optional — leave it blank to keep your current password. A password strength indicator and complexity requirements are shown below the input.</p><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><p>Switch the UI language between available locales. The change applies immediately after saving.</p><h2 id="timezone" tabindex="-1">Timezone <a class="header-anchor" href="#timezone" aria-label="Permalink to &quot;Timezone&quot;">​</a></h2><p>Set your preferred timezone for date/time displays (e.g., for the calendar heatmap and progress log timestamps). Your browser&#39;s detected timezone is shown as a reference.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Choose a custom DaisyUI theme from the dropdown. The theme previews in real-time as you browse the dropdown, and the selection is saved to your profile so it persists across sessions.</p><h2 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h2><p>Create and manage API keys for headless access to the REST API. Each key can have an optional description. Keys are shown once at creation — copy it immediately, as it cannot be retrieved later.</p><p>See the <a href="/librislog/next/guide/api-keys.html">API Keys guide</a> for detailed setup instructions.</p><h2 id="data-management" tabindex="-1">Data Management <a class="header-anchor" href="#data-management" aria-label="Permalink to &quot;Data Management&quot;">​</a></h2><p>Two data management tools are available:</p><ul><li><strong>Import / Export</strong> — Export your library as JSON, CSV, or ZIP, or import from Goodreads CSV or generic CSV with field mapping and Python transforms. See <a href="/librislog/next/guide/using-librislog/import-export.html">Import &amp; Export</a>.</li><li><strong>Data Hygiene</strong> — Find books with missing metadata and batch-update them. See <a href="/librislog/next/guide/using-librislog/data-hygiene.html">Data Hygiene</a>.</li></ul><h2 id="oidc" tabindex="-1">OIDC <a class="header-anchor" href="#oidc" aria-label="Permalink to &quot;OIDC&quot;">​</a></h2><p>If the instance has OIDC authentication enabled, you can link or unlink your account to an external identity provider.</p><h2 id="danger-zone" tabindex="-1">Danger Zone <a class="header-anchor" href="#danger-zone" aria-label="Permalink to &quot;Danger Zone&quot;">​</a></h2><p>Two irreversible actions are available:</p><h3 id="reset-my-data" tabindex="-1">Reset My Data <a class="header-anchor" href="#reset-my-data" aria-label="Permalink to &quot;Reset My Data&quot;">​</a></h3><p>Deletes all your books, reading progress, and tags. Your account and profile settings are preserved. Type the confirmation phrase to enable the button.</p><h3 id="delete-account" tabindex="-1">Delete Account <a class="header-anchor" href="#delete-account" aria-label="Permalink to &quot;Delete Account&quot;">​</a></h3><p>Permanently deletes your account and all associated data. Type the confirmation phrase to enable the button. After deletion, you are redirected to the login page.</p>',25)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
